function seasonFromGameId(gameId){const m=String(gameId||'').match(/^(\d{4}-S\d+)\s+G(\d+)/i);return m?{season_id:m[1],game_number:Number(m[2])}:null}
function ensureSeasons(d){d=d||clone(DEFAULT_DATA);d.seasons=d.seasons||[];const defaultSeason='2026-S2';const games=d.games||[];const hasSeasoned=games.some(g=>String(g.game_id||'').match(/^\d{4}-S\d+\s+G\d+/i));
  if(!hasSeasoned && games.some(g=>/^G\d+$/i.test(String(g.game_id||'')))){
    const remap={};games.forEach(g=>{if(/^G\d+$/i.test(String(g.game_id||''))){const old=String(g.game_id);const num=old.replace(/^G/i,'');const nid=`${defaultSeason} G${num}`;remap[old]=nid;g.game_id=nid;g.season_id=defaultSeason;g.game_number=Number(num)||null;}});
    ['shots','events','freeThrows','lineupStints'].forEach(arr=>(d[arr]||[]).forEach(r=>{if(remap[r.game_id])r.game_id=remap[r.game_id]}));
    (d.activityLog||[]).forEach(r=>{if(remap[r.game_id])r.game_id=remap[r.game_id]});
  }
  games.forEach((g,i)=>{const parsed=seasonFromGameId(g.game_id);g.season_id=g.season_id||parsed?.season_id||defaultSeason;g.game_number=g.game_number||parsed?.game_number||i+1;if(!/^\d{4}-S\d+\s+G\d+/i.test(String(g.game_id||'')))g.game_id=`${g.season_id} G${g.game_number}`;});
  const ids=new Set(d.seasons.map(s=>s.season_id));games.forEach(g=>{if(g.season_id&&!ids.has(g.season_id)){d.seasons.push({season_id:g.season_id,label:g.season_id,year:String(g.season_id).slice(0,4),season:String(g.season_id).split('-S')[1]||'',notes:''});ids.add(g.season_id);}});
  d.currentSeason=d.currentSeason||games[0]?.season_id||defaultSeason;return d}
function normalizeData(d){d=ensureSeasons(d||clone(DEFAULT_DATA));(d.shots||[]).forEach(s=>{const currentZone=String(s.shot_zone||'').toLowerCase();if(currentZone==='deep top 3')s.shot_zone='top 3';if(['midrange','long midrange','left midrange','middle midrange','right midrange'].includes(currentZone)&&s.shot_x!==undefined&&s.shot_x!==null&&s.shot_y!==undefined&&s.shot_y!==null){const z=zoneFromXY(s.shot_x,s.shot_y);s.shot_zone=z.zone;s.approx_distance_m=z.dist}});return d}
