function selectedShotPopup(s,x,y){
  const w=6.25;
  const line1=popupText(`${s.player||''} · ${s.result||''} · ${s.points||''}PT`,30);
  const line2=popupText(`${s.shot_zone||''} · ${s.shot_type||''}`,34);
  const detail=[s.contest||'',s.assisted_by?`AST ${s.assisted_by}`:'',s.screen_assist_by?`screen ${s.screen_assist_by}`:''].filter(Boolean).join(' · ');
  const line3=popupText(detail,34);
  const h=line3?1.38:1.04;
  let tx=(x>8.8)?x-w-0.36:x+0.36;
  tx=Math.min(Math.max(tx,0.10),15.0-w-0.10);
  let ty=(y>1.45)?y-1.26:y+0.40;
  ty=Math.min(Math.max(ty,0.10),14.0-h-0.10);
  return `<g class="shot-popup"><rect class="shot-popup-bg" x="${tx}" y="${ty}" width="${w}" height="${h}" rx="0.14"/><text class="shot-popup-text" x="${tx+0.18}" y="${ty+0.39}">${esc(line1)}</text><text class="shot-popup-sub" x="${tx+0.18}" y="${ty+0.76}">${esc(line2)}</text>${line3?`<text class="shot-popup-sub" x="${tx+0.18}" y="${ty+1.10}">${esc(line3)}</text>`:''}</g>`
}
