function scopeAllRows(gameId,half,seasonId='ALL'){return{shots:scopeRows(data.shots,{gameId,half,seasonId}),events:scopeRows(data.events,{gameId,half,seasonId}),fts:scopeRows(data.freeThrows,{gameId,half,seasonId}),lineups:scopeRows(data.lineupStints,{gameId,half,seasonId})}}
function countMissing(rows,fields){return rows.filter(r=>fields.some(f=>r[f]===undefined||r[f]===null||String(r[f]).trim()==='')).length}
function knownPlayerSet(){return new Set((data.players||[]).map(p=>p.name||p.player||p.player_name).filter(Boolean))}
function knownGameSet(){return new Set((data.games||[]).map(g=>g.game_id).filter(Boolean))}
function trackingQualityHtml(gameId,half,seasonId='ALL'){const rows=scopeAllRows(gameId,half,seasonId);const ps=knownPlayerSet(),gs=knownGameSet();const warnings=[];const missingShotPlayer=countMissing(rows.shots,['player']);const missingShotLocation=rows.shots.filter(s=>s.shot_x===''||s.shot_y===''||s.shot_x==null||s.shot_y==null||!s.shot_zone).length;const missingShotContext=rows.shots.filter(s=>!s.shot_type||!s.contest).length;const missingEventCore=rows.events.filter(e=>!e.player||!e.event_type).length;const missingFtCore=rows.fts.filter(f=>!f.player||!f.result).length;const lineupBadHalf=rows.lineups.filter(l=>!['1H','2H','OT','ALL',''].includes(String(l.half||''))).length;const lineupMissingPlayers=rows.lineups.filter(l=>![l.player_1,l.player_2,l.player_3,l.player_4,l.player_5].every(Boolean)).length;const unknownShotPlayers=rows.shots.filter(s=>s.player&&!ps.has(s.player)).length;const unknownEventPlayers=rows.events.filter(e=>e.player&&!ps.has(e.player)).length;const unknownGames=[...data.shots||[],...data.events||[],...data.freeThrows||[],...data.lineupStints||[]].filter(r=>r.game_id&&!gs.has(r.game_id)).length;if(missingShotPlayer)warnings.push(`${missingShotPlayer} shot row(s) have no player.`);if(missingShotLocation)warnings.push(`${missingShotLocation} shot row(s) are missing x/y location or zone.`);if(missingShotContext)warnings.push(`${missingShotContext} shot row(s) are missing shot type or contest.`);if(missingEventCore)warnings.push(`${missingEventCore} event row(s) are missing player or event type.`);if(missingFtCore)warnings.push(`${missingFtCore} free throw row(s) are missing player or result.`);if(lineupBadHalf)warnings.push(`${lineupBadHalf} lineup stint(s) have an unusual half label. Example from the old Excel import: half = result should be fixed later.`);if(lineupMissingPlayers)warnings.push(`${lineupMissingPlayers} lineup stint(s) do not have all five players filled.`);if(unknownShotPlayers||unknownEventPlayers)warnings.push(`${unknownShotPlayers+unknownEventPlayers} shot/event player value(s) are not in the roster list.`);if(unknownGames)warnings.push(`${unknownGames} row(s) use a game_id that is not in the Games list.`);const card=(label,main,sub,cls='')=>`<div class="quality-card ${cls}"><div class="label">${esc(label)}</div><div class="main">${main}</div><div class="sub">${sub}</div></div>`;const quality=warnings.length?'warn':'';return `<div class="quality-grid">${card('Shots',rows.shots.length,`${missingShotLocation} missing location/zone · ${missingShotContext} missing context`,missingShotLocation||missingShotContext?'warn':'')}${card('Events',rows.events.length,`${missingEventCore} missing core fields`,missingEventCore?'warn':'')}${card('Free throws',rows.fts.length,`${missingFtCore} missing core fields`,missingFtCore?'warn':'')}${card('Lineups',rows.lineups.length,`${lineupBadHalf} bad half labels · ${lineupMissingPlayers} incomplete`,lineupBadHalf||lineupMissingPlayers?'warn':'')}${card('Overall',warnings.length?`${warnings.length} warning${warnings.length===1?'':'s'}`:'Clean',warnings.length?'Fix before using as final report':'No obvious data issues for this filter',warnings.length?'warn':'')}</div>${warnings.length?`<div class="quality-warnings"><b>Warnings to review</b><ul>${warnings.map(w=>`<li>${esc(w)}</li>`).join('')}</ul></div>`:`<p class="small muted" style="margin-top:8px">No obvious completeness issues found for the selected report filter.</p>`}`}


