q('quickJsonBtn').onclick=()=>download('basketball-data-v0.4.14.json',JSON.stringify(data,null,2),'application/json');q('downloadJsonBtn').onclick=q('quickJsonBtn').onclick;q('downloadHtmlBtn').onclick=()=>download('basketball-tracker-v0.4.14-saved.html',htmlWithCurrentData(),'text/html');q('importJsonBtn').onclick=()=>q('jsonFile').click();q('jsonFile').onchange=e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=()=>{try{const imported=JSON.parse(r.result);data=normalizeData(imported);data.activityLog=data.activityLog||[];saveData();q('jsonFile').value='';alert('Imported JSON and replaced current browser data.');}catch(err){alert('JSON import error: '+err.message)}};r.readAsText(f)};q('clearRecentLogBtn').onclick=()=>{if(confirm('Clear the recent tracking log only? This will NOT delete shots, events, free throws, or lineups.')){data.activityLog=[];saveData()}};q('clearBrowserSaveBtn').onclick=()=>{if(confirm('Clear this browser save and reload the default embedded data? Download JSON first if you need a backup.')){localStorage.removeItem(STORAGE_KEY);localStorage.removeItem(STATE_KEY);data=normalizeData(clone(DEFAULT_DATA));state={};renderAll();q('saveState').textContent='Browser save cleared'}};q('copyAllBtn').onclick=()=>copy(['SHOTS',tsv(data.shots,cols('shots')),'','EVENTS',tsv(data.events,cols('events')),'','FREE_THROWS',tsv(data.freeThrows,cols('fts')),'','LINEUPS',tsv(data.lineupStints,cols('lineups'))].join('\n'));
function ensureSeasonRecord(season){data.seasons=data.seasons||[];if(!(data.seasons||[]).some(s=>s.season_id===season)){data.seasons.push({season_id:season,label:season,year:String(season).slice(0,4),season:String(season).split('-S')[1]||'',notes:''})}}
function nextGameNumberForSeason(season){const nums=(data.games||[]).filter(g=>(g.season_id||seasonFromGameId(g.game_id)?.season_id)===season).map(g=>num(g.game_number)||seasonFromGameId(g.game_id)?.game_number||0);return Math.max(0,...nums)+1}
function addGameFlow(){const season=prompt('Season ID? Example: 2026-S2',currentSeason())||currentSeason();if(!season)return;ensureSeasonRecord(season);const suggested=nextGameNumberForSeason(season);const nRaw=prompt('Game number? Example: 2',String(suggested));if(nRaw===null)return;const parsedFull=String(nRaw).match(/^(\d{4}-S\d+)\s+G(\d+)$/i);const finalSeason=parsedFull?parsedFull[1]:season;const numText=parsedFull?parsedFull[2]:String(nRaw).replace(/^G/i,'').trim();if(!numText)return;const gid=`${finalSeason} G${numText}`;if((data.games||[]).some(g=>g.game_id===gid))return alert('That game already exists: '+gid);ensureSeasonRecord(finalSeason);const date=prompt('Game date? YYYY-MM-DD',new Date().toISOString().slice(0,10));if(date===null)return;const opp=prompt('Opponent?', '')||'';const teamScore=prompt('Our score? Leave 0 if tracking live.', '0');if(teamScore===null)return;const oppScore=prompt('Opponent score? Leave 0 if tracking live.', '0');if(oppScore===null)return;const result=prompt('Result? W/L or leave blank until final.', '')||'';data.games=data.games||[];data.games.push({game_id:gid,season_id:finalSeason,game_number:Number(numText)||null,date:date||'',opponent:opp,team_score:num(teamScore),opponent_score:num(oppScore),result:result,notes:''});state.seasonId=finalSeason;state.gameId=gid;state.half='1H';data.currentSeason=finalSeason;saveState();clearShot(true);saveData();alert('Added '+gid+'. It is now the current tracking game and the shot clicker starts blank.')}
function editCurrentGameFlow(){const gid=currentGame();const g=(data.games||[]).find(x=>x.game_id===gid);if(!g)return alert('No current game found. Add a game first.');const date=prompt('Game date? YYYY-MM-DD',g.date||'');if(date===null)return;const opp=prompt('Opponent?',g.opponent||'');if(opp===null)return;const teamScore=prompt('Our score?',String(g.team_score??0));if(teamScore===null)return;const oppScore=prompt('Opponent score?',String(g.opponent_score??0));if(oppScore===null)return;const result=prompt('Result? W/L or blank',g.result||'');if(result===null)return;g.date=date;g.opponent=opp;g.team_score=num(teamScore);g.opponent_score=num(oppScore);g.result=result;g.season_id=g.season_id||seasonFromGameId(g.game_id)?.season_id||currentSeason();g.game_number=g.game_number||seasonFromGameId(g.game_id)?.game_number||null;saveData();alert('Updated '+gid)}
q('downloadCsvZipBtn').onclick=downloadCsvPack;['addGameBtn','addGameBtnTrack'].forEach(id=>{if(q(id))q(id).onclick=addGameFlow});['editGameBtn','editGameBtnTrack'].forEach(id=>{if(q(id))q(id).onclick=editCurrentGameFlow});q('addPlayerBtn').onclick=()=>{const name=prompt('Player name?');if(!name)return;data.players=data.players||[];data.players.push({player_id:name,name,jersey:'',position:'',active:true,notes:''});saveData()};q('resetAllBtn').onclick=()=>{if(confirm('Clear local tracker data and restore migrated default?')){data=normalizeData(clone(DEFAULT_DATA));state={};saveState();saveData()}};
if(q('downloadReportBtn'))q('downloadReportBtn').onclick=()=>download('spartans-interactive-report-v0.4.17.1.html',buildReportHtml(),'text/html');if(q('downloadLockedGameReportBtn'))q('downloadLockedGameReportBtn').onclick=()=>{const game=q('report_game')?.value||'ALL';if(game==='ALL')return alert('Choose a specific game first, then download the locked-game report.');const safe=String(game).replace(/[^A-Za-z0-9]+/g,'-').replace(/^-|-$/g,'').toLowerCase();download('spartans-'+safe+'-interactive-report.html',buildReportHtml({lockGame:true}),'text/html')};q('regionOverlayToggle').onclick=toggleRegionOverlay;q('saveReportNotesBtn').onclick=saveReportNotes;q('reportNotesInput').onchange=saveReportNotes;q('report_season').onchange=()=>{updateGameSelectForSeason('report_season','report_game',true);q('report_game').value='ALL';renderReports()};q('report_game').onchange=renderReports;q('report_half').onchange=renderReports;q('report_player').onchange=renderReports;if(q('advanced_season'))q('advanced_season').onchange=()=>{updateGameSelectForSeason('advanced_season','advanced_game',true);q('advanced_game').value='ALL';renderAdvancedStats()};['advanced_game','advanced_half','advanced_view','advanced_player','advanced_mode'].forEach(id=>{if(q(id))q(id).onchange=renderAdvancedStats});if(q('quality_season'))q('quality_season').onchange=()=>{updateGameSelectForSeason('quality_season','quality_game',true);q('quality_game').value='ALL';renderQuality()};if(q('quality_game'))q('quality_game').onchange=renderQuality;if(q('quality_half'))q('quality_half').onchange=renderQuality;if(q('refreshQualityBtn'))q('refreshQualityBtn').onclick=renderQuality;q('jsonBox').onchange=()=>{try{data=JSON.parse(q('jsonBox').value);saveData()}catch(e){alert('JSON error: '+e.message)}};
